using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.ApiTests;/// <summary>/// Good case: Get audit logs by patient/// Expected: 200 OK with paged list/// </summary>public class AuditServiceTests_GetAuditLogsByPatient_WithValidPatient_ShouldReturnLogs : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {        "AuthService",        "AuditService"    };    [SkippableFact]    public async Task GetAuditLogsByPatient_WithValidPatient_ShouldReturnLogs()    {        await AuthenticateAsAdminAsync(AuditClient);        var response = await GetWithRetryAsync(            AuditClient,             ApiEndpoints.Audit.ByPatient(TestSeedData.PatientUserId));        Assert.Equal(HttpStatusCode.OK, response.StatusCode);                var json = await ReadJsonResponseAsync(response);        Assert.True(json.ValueKind == JsonValueKind.Object);    }}
